**JavaScript (Dynamic):**
```javascript
function add(a, b) {
  return a + b;
}
// Works fine:
console.log(add(1, 2)); // 3
// Accidental error:
console.log(add("1", 2)); // "12" (String concatenation)
```

**TypeScript (Static):**
```typescript
function add(a: number, b: number): number {
  return a + b;
}
// Works fine:
console.log(add(1, 2));
// Compile Error:
console.log(add("1", 2)); 
// Error: Argument of type 'string' is not assignable to parameter of type 'number'.
```

#### Example: Duck Typing in JavaScript
```javascript
function makeItFly(thing) {
  // We don't care if 'thing' is a Bird, a Plane, or a Rocket.
  // We only care that it has a .fly() method.
  thing.fly();
}

class Bird {
  fly() { console.log("Flap flap!"); }
}

class Airplane {
  fly() { console.log("Zoom zoom!"); }
}

#### TypeScript Structural Typing Example
```typescript
// Define the "Duck" shape
interface Quacker {
  quack(): void;
}

// This function expects a Quacker
function makeSound(animal: Quacker) {
  animal.quack();
}

// A Dog class that doesn't inherit from Quacker
class Dog {
  quack() { console.log("Woof quack!"); }
}

// A literal object
const rubberDuck = {
  quack: () => console.log("Squeak!")
};

